import React, { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';
import Dashboard from './Dashboard';
import { submitManualData } from './api';

function App() {
    const [user, setUser] = useState(null);
    const [view, setView] = useState('choice'); 
    const [isLoading, setIsLoading] = useState(false);
    
    // Data States
    const [analysisData, setAnalysisData] = useState(null);
    const [productName, setProductName] = useState('');
    const [dietHistory, setDietHistory] = useState([]);

    // Auth & Form States
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [barcode, setBarcode] = useState('');
    const [manualEntry, setManualEntry] = useState({ name: '', sugar: '', protein: '', fat: '' });

    // Quiz States
    const [goal, setGoal] = useState('Energy');
    const [symptoms, setSymptoms] = useState([]);
    const goals = ["Energy", "Immunity", "Cognitive Focus", "Skin Health", "Muscle Recovery", "Longevity", "Gut Health"];
    const symptomList = ["Fatigue", "Stress", "Poor Sleep", "Muscle Cramps", "Brain Fog", "Joint Pain", "Brittle Nails", "Anxiety", "Dry Eyes", "Bloating"];

    useEffect(() => {
        supabase.auth.getSession().then(({ data: { session } }) => setUser(session?.user ?? null));
        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            setUser(session?.user ?? null);
            if (session?.user) setView('choice');
        });
        return () => subscription.unsubscribe();
    }, []);

    // --- NAVIGATION & CLEANUP ---
    const goHome = () => {
        setAnalysisData(null);
        setProductName('');
        setBarcode('');
        setSymptoms([]);
        setView('choice');
    };

    // --- LOGIC HANDLERS ---
    const fetchDietPlan = async () => {
        setIsLoading(true);
        const { data, error } = await supabase.from('diet_logs').select('*').order('created_at', { ascending: false });
        if (!error) setDietHistory(data);
        setView('view_plan');
        setIsLoading(false);
    };

    const handleBarcodeSearch = async (val = barcode) => {
        if (!val) return;
        setIsLoading(true);
        try {
            const response = await fetch(`http://localhost:8000/scan-barcode/${val}`);
            const result = await response.json();
            if (result.status === "success") { setAnalysisData(result.data); setProductName(result.product_name); }
        } catch (err) { alert("Barcode search failed"); }
        finally { setIsLoading(false); }
    };

    const handlePhotoUpload = async (e) => {
        const file = e.target.files[0];
        if (!file) return;
        setIsLoading(true);
        const formData = new FormData();
        formData.append("file", file);
        try {
            const response = await fetch("http://localhost:8000/upload-barcode-photo", { method: "POST", body: formData });
            const result = await response.json();
            if (result.status === "success") { setAnalysisData(result.data); setProductName(result.product_name); }
        } catch (err) { alert("Photo analysis failed"); }
        finally { setIsLoading(false); }
    };

    const handleQuizSubmit = async () => {
        setIsLoading(true);
        try {
            const response = await submitManualData({ goal, symptoms });
            setAnalysisData(response.data);
            setProductName("Personal Health Profile");
        } catch (err) { alert("Quiz failed"); }
        finally { setIsLoading(false); }
    };

    const saveToDietPlan = async (customData = null) => {
        const entry = customData || { product_name: productName, analysis_json: analysisData, user_id: user.id };
        const { error } = await supabase.from('diet_logs').insert([entry]);
        if (error) alert(error.message);
        else { alert("Added to plan!"); fetchDietPlan(); }
    };

    // --- UI HELPERS ---
    const MenuCard = ({ icon, title, desc, onClick }) => (
        <div style={styles.optionCard} onClick={onClick}>
            <div style={styles.cardIcon}>{icon}</div>
            <div style={styles.cardContent}>
                <h3 style={styles.cardTitle}>{title}</h3>
                <p style={styles.cardDesc}>{desc}</p>
            </div>
        </div>
    );

    if (!user) {
        return (
            <div style={styles.container}>
                <h1 style={styles.logoText}>NutriGen<span style={{color: '#38a169'}}>.</span></h1>
                <div style={styles.authCard}>
                    <input style={styles.input} placeholder="Email" onChange={e => setEmail(e.target.value)} />
                    <input style={styles.input} type="password" placeholder="Password" onChange={e => setPassword(e.target.value)} />
                    <button style={styles.primaryBtn} onClick={() => supabase.auth.signInWithPassword({email, password})}>Login</button>
                    <button style={{...styles.primaryBtn, background: '#444', marginTop: '10px'}} onClick={() => supabase.auth.signUp({email, password})}>Sign Up</button>
                </div>
            </div>
        );
    }

    return (
        <div style={styles.container}>
            <header style={styles.nav}>
                {/* 1) CLICKABLE LOGO TO RETURN HOME */}
                <h1 style={styles.logoText} onClick={goHome}>
                    NutriGen<span style={{color: '#38a169'}}>.</span>
                </h1>
                <button onClick={() => supabase.auth.signOut()} style={styles.logoutBtn}>Logout</button>
            </header>

            <main>
                {analysisData ? (
                    <div style={styles.resultsHeader}>
                        <h2 style={styles.productTitle}>{productName}</h2>
                        <div style={{display: 'flex', gap: '10px', marginBottom: '20px'}}>
                            <button style={styles.primaryBtn} onClick={() => saveToDietPlan()}>Add to Plan</button>
                            <button style={styles.secondaryBtn} onClick={() => setAnalysisData(null)}>Discard</button>
                        </div>
                        <Dashboard data={analysisData} onReset={() => setAnalysisData(null)} />
                    </div>
                ) : view === 'choice' ? (
                    <div style={styles.menuGrid}>
                        <MenuCard icon="🔍" title="Barcode Search" desc="Scan product barcodes or upload photos to analyze ingredients." onClick={() => setView('scan')} />
                        <MenuCard icon="📅" title="Diet Plan" desc="Track your daily nutrition and view your saved food history." onClick={fetchDietPlan} />
                        <MenuCard icon="🧬" title="Health Quiz" desc="Answer a few questions to get tailored dietary advice." onClick={() => setView('quiz')} />
                    </div>
                ) : view === 'scan' ? (
                    <div style={styles.card}>
                        <h3>Product Scanner</h3>
                        <p style={styles.cardDesc}>Upload a photo of a barcode or type the number below.</p>
                        <input style={styles.input} placeholder="Enter Barcode Number" value={barcode} onChange={e => setBarcode(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleBarcodeSearch()} />
                        <button style={styles.primaryBtn} onClick={() => handleBarcodeSearch()}>Analyze Number</button>
                        <div style={{margin: '20px 0', color: '#444', textAlign: 'center'}}>OR</div>
                        <input type="file" id="barcode-photo" hidden accept="image/*" onChange={handlePhotoUpload} />
                        <label htmlFor="barcode-photo" style={styles.btnSecondary}>
                            {isLoading ? "Processing..." : "📷 Upload Barcode Photo"}
                        </label>
                        <button style={styles.backBtn} onClick={() => setView('choice')}>Back to Menu</button>
                    </div>
                ) : view === 'quiz' ? (
                    <div style={styles.card}>
                        <h3>Health Assessment</h3>
                        <p style={styles.cardDesc}>Analyze flags based on your personal health goals.</p>
                        <label style={styles.label}>Primary Goal:</label>
                        <select value={goal} onChange={(e) => setGoal(e.target.value)} style={styles.input}>
                            {goals.map(g => <option key={g} value={g}>{g}</option>)}
                        </select>
                        <label style={styles.label}>Symptoms:</label>
                        <div style={{display: 'flex', gap: '8px', flexWrap: 'wrap', marginTop: '10px'}}>
                            {symptomList.map(s => (
                                <button key={s} onClick={() => setSymptoms(prev => prev.includes(s) ? prev.filter(i => i !== s) : [...prev, s])} 
                                    style={symptoms.includes(s) ? styles.tagActive : styles.tag}>{s}</button>
                            ))}
                        </div>
                        <button onClick={handleQuizSubmit} style={{...styles.primaryBtn, marginTop: '30px'}}>{isLoading ? 'Analyzing...' : 'Generate Analysis'}</button>
                        <button style={styles.backBtn} onClick={() => setView('choice')}>Cancel</button>
                    </div>
                ) : view === 'view_plan' ? (
                    <div style={styles.planView}>
                        <div style={styles.planHeader}>
                            <h2>My Diet Plan</h2>
                            <button style={styles.primaryBtn} onClick={() => setView('manual_log')}>+ Manual Item</button>
                        </div>
                        {dietHistory.length === 0 ? <p style={{color: '#444'}}>No items saved yet.</p> : dietHistory.map(item => (
                            <div key={item.id} style={styles.historyItem}>
                                <strong>{item.product_name}</strong>
                                <span style={{color: '#555', fontSize: '0.8rem'}}> — {new Date(item.created_at).toLocaleDateString()}</span>
                            </div>
                        ))}
                        <button style={styles.backBtn} onClick={() => setView('choice')}>← Menu</button>
                    </div>
                ) : view === 'manual_log' ? (
                    <div style={styles.card}>
                        <h3>Manual Log</h3>
                        <input style={styles.input} placeholder="Food Name" onChange={e => setManualEntry({...manualEntry, name: e.target.value})} />
                        <div style={{display: 'flex', gap: '10px'}}>
                            <input style={styles.input} type="number" placeholder="Sugar (g)" onChange={e => setManualEntry({...manualEntry, sugar: e.target.value})} />
                            <input style={styles.input} type="number" placeholder="Protein (g)" onChange={e => setManualEntry({...manualEntry, protein: e.target.value})} />
                        </div>
                        <button style={styles.primaryBtn} onClick={() => saveToDietPlan({
                            product_name: manualEntry.name, user_id: user.id,
                            analysis_json: [{ rsid: `Sugar: ${manualEntry.sugar}g`, trait: "Manual", genotype: "User Input", recommendation: "Logged manually." }]
                        })}>Save Item</button>
                        <button style={styles.backBtn} onClick={() => setView('view_plan')}>Back</button>
                    </div>
                ) : null}
            </main>
        </div>
    );
}

const styles = {
    container: { maxWidth: '900px', margin: '0 auto', padding: '40px 20px', color: '#fff', fontFamily: "system-ui, -apple-system, sans-serif" },
    nav: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '50px' },
    logoText: { fontSize: '2rem', fontWeight: '900', cursor: 'pointer', margin: 0, userSelect: 'none' },
    authCard: { background: '#111', padding: '30px', borderRadius: '20px', border: '1px solid #222' },
    menuGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '20px' },
    optionCard: { background: '#111', padding: '30px', borderRadius: '24px', border: '1px solid #222', cursor: 'pointer', transition: '0.2s', display: 'flex', flexDirection: 'column', gap: '10px' },
    cardIcon: { fontSize: '2rem' },
    cardTitle: { margin: 0, fontSize: '1.25rem' },
    cardDesc: { margin: 0, color: '#666', fontSize: '0.9rem', lineHeight: '1.5' },
    card: { background: '#111', padding: '40px', borderRadius: '24px', border: '1px solid #222' },
    input: { width: '100%', padding: '14px', margin: '10px 0', borderRadius: '12px', background: '#000', border: '1px solid #333', color: '#fff', boxSizing: 'border-box' },
    primaryBtn: { background: '#38a169', color: '#fff', padding: '14px 24px', borderRadius: '12px', border: 'none', fontWeight: 'bold', cursor: 'pointer', width: '100%' },
    btnSecondary: { background: '#222', color: '#fff', padding: '14px', borderRadius: '12px', textAlign: 'center', cursor: 'pointer', display: 'block', width: '100%', boxSizing: 'border-box' },
    backBtn: { background: 'none', border: 'none', color: '#555', cursor: 'pointer', marginTop: '20px', textDecoration: 'underline', width: '100%' },
    label: { display: 'block', margin: '20px 0 5px 0', color: '#888', fontWeight: 'bold' },
    tag: { padding: '8px 16px', borderRadius: '20px', border: '1px solid #333', background: '#000', color: '#666', cursor: 'pointer' },
    tagActive: { padding: '8px 16px', borderRadius: '20px', border: '1px solid #38a169', background: 'rgba(56, 161, 105, 0.1)', color: '#38a169' },
    historyItem: { background: '#000', padding: '15px 20px', borderRadius: '12px', border: '1px solid #222', marginBottom: '10px', display: 'flex', justifyContent: 'space-between' },
    planHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' },
    logoutBtn: { border: '1px solid #222', background: 'none', color: '#444', padding: '8px 16px', borderRadius: '10px', cursor: 'pointer' },
    productTitle: { color: '#38a169', textAlign: 'center', textTransform: 'capitalize' }
};

export default App;
